import React, { useState, useEffect } from 'react';
import { useAuth } from './hooks/useAuth';
import { useCart } from './hooks/useCart';
import { useProducts } from './hooks/useProducts';

import HomePage       from './pages/HomePage';
import LoginPage      from './pages/LoginPage';
import RegisterPage   from './pages/RegisterPage';
import ProductsPage   from './pages/ProductsPage';
import CartPage       from './pages/CartPage';
import CheckoutPage   from './pages/CheckoutPage';
import OrdersPage     from './pages/OrdersPage';
import ProfilePage    from './pages/ProfilePage';
import AdminDashboard from './pages/admin/AdminDashboard';

const App = () => {
  // Start with 'home' — the correct page will be set once isInitializing
  // flips to false (see the useEffect below that reads currentPage from storage).
  const [currentPage,  setCurrentPage]  = useState('home');
  const [searchQuery,  setSearchQuery]  = useState('');
  const [error,        setError]        = useState('');
  const [loading,      setLoading]      = useState(false);

  const auth         = useAuth();
  const cartHook     = useCart(auth.user);
  const productsHook = useProducts();

  // ── After rehydration completes, restore the correct page ──────────────
  // We intentionally do NOT read currentPage from storage at module load
  // time (the old getInitialPage() pattern). Doing so would sometimes
  // restore a page that belongs to a cleared/restarted session before the
  // auth check has finished. Instead we wait for isInitializing = false,
  // then let the routing logic below decide what is safe to show.
  useEffect(() => {
    if (auth.isInitializing) return;

    const saved =
      sessionStorage.getItem('currentPage') ||
      localStorage.getItem('currentPage')   ||
      'home';

    if (!auth.user) {
      // Not authenticated — only public pages are allowed
      const publicPages = ['home', 'login', 'register'];
      setCurrentPage(publicPages.includes(saved) ? saved : 'home');
      return;
    }

    if (auth.user.role === 'Admin') {
      const adminPages = ['admin', 'products'];
      setCurrentPage(adminPages.includes(saved) ? saved : 'admin');
    } else {
      // Customer — never land on admin page
      const blockedPages = ['admin'];
      setCurrentPage(blockedPages.includes(saved) ? 'products' : saved);
    }
  }, [auth.isInitializing]); // runs exactly once, when the auth check finishes

  // ── Persist currentPage whenever it changes (after init) ───────────────
  useEffect(() => {
    if (auth.isInitializing) return;
    sessionStorage.setItem('currentPage', currentPage);
    localStorage.setItem('currentPage',   currentPage);
  }, [currentPage, auth.isInitializing]);

  // ── Load user data whenever the user object becomes available ──────────
  useEffect(() => {
    if (auth.user) loadUserData();
  }, [auth.user]);

  const loadUserData = async () => {
    if (!auth.user) return;
    try {
      await Promise.all([
        productsHook.loadProducts().catch(err => console.warn('⚠️ products:', err)),
        cartHook.loadCart().catch(err =>         console.warn('⚠️ cart:', err)),
        auth.loadProfile().catch(err =>          console.warn('⚠️ profile:', err)),
        auth.loadOrders().catch(err =>           console.warn('⚠️ orders:', err))
      ]);
    } catch (err) {
      console.error('❌ Error loading user data:', err);
    }
  };

  const pageProps = {
    currentPage, setCurrentPage,
    searchQuery, setSearchQuery,
    error, setError,
    loading, setLoading,
    user:           auth.user,
    setUser:        auth.setUser,
    cart:           cartHook.cart,
    setCart:        cartHook.setCart,
    products:       productsHook.products,
    setProducts:    productsHook.setProducts,
    orders:         auth.orders,
    setOrders:      auth.setOrders,
    handleLogout:   auth.handleLogout,
    addToCart:      cartHook.addToCart,
    updateCartQuantity: cartHook.updateCartQuantity,
    removeFromCart: cartHook.removeFromCart,
    clearCart:      cartHook.clearCart,
    profileData:    auth.profileData,
    setProfileData: auth.setProfileData,
    loadProducts:   productsHook.loadProducts,
    loadOrders:     auth.loadOrders,
    loadProfile:    auth.loadProfile
  };

  // ── Loading spinner — blocks render until auth check is done ───────────
  if (auth.isInitializing) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-teal-500 border-t-transparent rounded-full animate-spin" />
          <p className="text-slate-600 font-semibold text-lg">Loading ShopAI...</p>
        </div>
      </div>
    );
  }

  // ── Unauthenticated routes ──────────────────────────────────────────────
  if (!auth.user) {
    if (currentPage === 'login')    return <LoginPage    {...pageProps} />;
    if (currentPage === 'register') return <RegisterPage {...pageProps} />;
    return <HomePage {...pageProps} />;
  }

  // ── Authenticated routes ────────────────────────────────────────────────
  if (auth.user.role === 'Admin' && currentPage === 'admin') {
    return <AdminDashboard {...pageProps} />;
  }

  switch (currentPage) {
    case 'products': return <ProductsPage  {...pageProps} />;
    case 'cart':     return <CartPage      {...pageProps} />;
    case 'checkout': return <CheckoutPage  {...pageProps} />;
    case 'orders':   return <OrdersPage    {...pageProps} />;
    case 'profile':  return <ProfilePage   {...pageProps} />;
    default:         return <ProductsPage  {...pageProps} />;
  }
};

export default App;
